3_real_world_example.code:
const originalObj = { name: 'SkillSprint' };
const copyObj = originalObj; // Copies the HEAP address pointer, not the object!

copyObj.name = 'Updated';
console.log(originalObj.name); // 'Updated'  (Both point to the same Heap object)

6_edge_case.code:
let a = { score: 10 };
let b = a;
b = { score: 20 }; // b now points to a completely new heap object
console.log(a.score); // 10 (original object remains unchanged)
